package com.practice.visual.service;
import com.practice.visual.entity.DashboardScreen;import com.practice.visual.dao.DashboardScreenDao;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class ScreenService { final DashboardScreenDao dao; public ScreenService(DashboardScreenDao dao){this.dao=dao;} @Transactional public DashboardScreen publish(Long id){DashboardScreen x=dao.findById(id).orElseThrow();x.published=true;x.status="PUBLISHED";x.configJson=filterTopology(x.configJson);return dao.save(x);} public String filterTopology(String json){ if(json==null)return null; return json.replaceAll(",?\\{[^{}]*\\\"type\\\"\\s*:\\s*\\\"topology\\\"[^{}]*\\}","").replace("[,", "[").replace(",]", "]"); } }
